/**
 * rugby-instagram.mjs — yt-dlp metadata extractor for Instagram rugby coaching posts
 *
 * Reads all Instagram URLs from Rugby/Rugby Links.md, fetches metadata via yt-dlp
 * (no video download), and caches results in .cache/rugby/<post_id>.json.
 *
 * Incremental: already-cached posts are skipped unless --force is passed.
 *
 * Usage (via router):
 *   node run.mjs rugby extract
 *   node run.mjs rugby extract --force      # re-fetch all
 *   node run.mjs rugby extract --limit 10   # only first N uncached
 *
 * Usage (direct):
 *   node scripts/pullers/rugby-instagram.mjs
 */

import { readFileSync, mkdirSync, writeFileSync, existsSync } from 'fs';
import { resolve, dirname, join } from 'path';
import { fileURLToPath } from 'url';
import { spawnSync } from 'child_process';

const __dirname = dirname(fileURLToPath(import.meta.url));
const VAULT_ROOT = resolve(__dirname, '..', '..');
const LINKS_FILE = join(VAULT_ROOT, 'Rugby', 'Rugby Links.md');
const CACHE_DIR  = join(VAULT_ROOT, '.cache', 'rugby');

const URL_RE = /https:\/\/www\.instagram\.com\/p\/([A-Za-z0-9_-]+)\/?/g;

function parseLinks(content) {
  const matches = [...content.matchAll(URL_RE)];
  return matches.map(m => ({ url: m[0].replace(/\/$/, '') + '/', post_id: m[1] }));
}

function fetchMetadata(url, useCookies) {
  const args = [
    '--skip-download',
    '--print-json',
    '--no-warnings',
    '--quiet',
  ];
  if (useCookies) {
    args.push('--cookies-from-browser', 'chrome');
  }
  args.push(url);

  const result = spawnSync('yt-dlp', args, { encoding: 'utf8', timeout: 30_000 });
  if (result.error) throw result.error;
  if (result.status !== 0) {
    const stderr = result.stderr?.trim() ?? '';
    throw new Error(stderr || `yt-dlp exited with code ${result.status}`);
  }
  return JSON.parse(result.stdout.trim());
}

function normaliseMetadata(raw, url, post_id) {
  return {
    post_id,
    url,
    title: raw.title ?? raw.fulltitle ?? '',
    description: raw.description ?? '',
    hashtags: raw.tags ?? [],
    uploader: raw.uploader ?? raw.channel ?? '',
    uploader_id: raw.uploader_id ?? raw.channel_id ?? '',
    upload_date: raw.upload_date ?? '',     // YYYYMMDD
    duration: raw.duration ?? null,
    view_count: raw.view_count ?? null,
    like_count: raw.like_count ?? null,
    fetched_at: new Date().toISOString(),
  };
}

export async function pull(flags = {}) {
  const force  = Boolean(flags.force);
  const limit  = flags.limit ? parseInt(flags.limit, 10) : Infinity;
  const dryRun = Boolean(flags['dry-run']);

  // Ensure cache directory exists
  mkdirSync(CACHE_DIR, { recursive: true });

  if (!existsSync(LINKS_FILE)) {
    console.error(`❌ Links file not found: ${LINKS_FILE}`);
    process.exit(1);
  }

  const content = readFileSync(LINKS_FILE, 'utf8');
  const links   = parseLinks(content);
  console.log(`\n🏉 Rugby Instagram Extractor`);
  console.log(`   Found ${links.length} URLs in Rugby Links.md\n`);

  let extracted = 0, skipped = 0, failed = 0;
  let processed = 0;

  for (const { url, post_id } of links) {
    if (processed >= limit) break;

    const cachePath = join(CACHE_DIR, `${post_id}.json`);
    if (!force && existsSync(cachePath)) {
      skipped++;
      continue;
    }

    processed++;
    if (dryRun) {
      console.log(`  [dry-run] Would fetch: ${url}`);
      extracted++;
      continue;
    }

    process.stdout.write(`  Fetching ${post_id}... `);
    let raw;
    try {
      raw = fetchMetadata(url, false);
    } catch (err) {
      // Retry with browser cookies (handles login-required posts)
      if (err.message.includes('login') || err.message.includes('private')) {
        process.stdout.write('(retrying with cookies) ');
        try {
          raw = fetchMetadata(url, true);
        } catch (err2) {
          console.log(`❌  ${err2.message.slice(0, 80)}`);
          failed++;
          continue;
        }
      } else {
        console.log(`❌  ${err.message.slice(0, 80)}`);
        failed++;
        continue;
      }
    }

    const meta = normaliseMetadata(raw, url, post_id);
    writeFileSync(cachePath, JSON.stringify(meta, null, 2), 'utf8');
    console.log(`✅  "${meta.title.slice(0, 60) || '(no title)'}"`);
    extracted++;
  }

  console.log(`\n📊 Summary`);
  console.log(`   Extracted : ${extracted}`);
  console.log(`   Skipped   : ${skipped} (already cached)`);
  console.log(`   Failed    : ${failed}`);
  console.log(`   Cache     : ${CACHE_DIR}\n`);
}

// Direct invocation
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  pull({}).catch(err => { console.error(err); process.exit(1); });
}

