/**
 * rugby-classify.mjs — LLM classifier for rugby Instagram coaching posts
 *
 * Reads raw metadata from .cache/rugby/<id>.json, classifies each post against
 * the versioned taxonomy in Rugby/taxonomy/rugby-skills.json, and writes
 * .cache/rugby/<id>-classified.json.
 *
 * Incremental: posts are skipped if their classified cache exists AND the
 * taxonomy_version matches. Bumping the version in rugby-skills.json triggers
 * reclassification of all posts.
 *
 * Uses Claude Haiku (cheap, fast, structured) via the Anthropic REST API.
 *
 * Usage:
 *   node run.mjs rugby classify
 *   node run.mjs rugby classify --force      # ignore cached classifications
 *   node run.mjs rugby classify --limit 20   # only first N
 *   node run.mjs rugby classify --dry-run    # print prompt, no API call
 */

import { readFileSync, writeFileSync, existsSync, readdirSync } from 'fs';
import { resolve, dirname, join, basename } from 'path';
import { fileURLToPath } from 'url';

const __dirname  = dirname(fileURLToPath(import.meta.url));
const VAULT_ROOT = resolve(__dirname, '..', '..');
const CACHE_DIR  = join(VAULT_ROOT, '.cache', 'rugby');
const TAXONOMY_FILE = join(VAULT_ROOT, 'Rugby', 'taxonomy', 'rugby-skills.json');

const ANTHROPIC_API_URL = 'https://api.anthropic.com/v1/messages';
const MODEL             = 'claude-haiku-4-5-20251001';
const BATCH_SIZE        = 10;
const BATCH_DELAY_MS    = 600;

function loadTaxonomy() {
  if (!existsSync(TAXONOMY_FILE)) {
    console.error(`❌ Taxonomy not found: ${TAXONOMY_FILE}`);
    process.exit(1);
  }
  return JSON.parse(readFileSync(TAXONOMY_FILE, 'utf8'));
}

function buildTaxonomyText(taxonomy) {
  const lines = ['Rugby Skill Taxonomy (use ONLY these exact terms):'];
  for (const [cat, skills] of Object.entries(taxonomy.categories)) {
    lines.push(`\nCategory: ${cat}`);
    for (const s of skills) lines.push(`  - ${s}`);
  }
  lines.push(`\nDifficulty levels: ${taxonomy.difficulty_levels.join(', ')}`);
  lines.push(`Age groups: ${taxonomy.age_groups.join(', ')}`);
  return lines.join('\n');
}

function buildPrompt(meta, taxonomyText) {
  const desc = (meta.description ?? '').slice(0, 800);
  const tags = (meta.hashtags ?? []).slice(0, 20).join(' ');
  const title = meta.title ?? '';

  return `You are a rugby coaching content classifier. Given an Instagram post about rugby coaching, classify it using the provided taxonomy.

${taxonomyText}

---
Post to classify:
Title: ${title}
Description: ${desc}
Hashtags: ${tags}
---

Return ONLY valid JSON matching this schema exactly:
{
  "skill_category": "<one of the category names above>",
  "sub_skill": "<one of the sub-skills within that category>",
  "canonical_term": "<the exact sub-skill name — same as sub_skill>",
  "coaching_cue": "<one actionable sentence a coach would say during this drill>",
  "age_groups": ["<applicable age groups from: Flag, Mini, Youth, Junior, Senior>"],
  "difficulty": "<beginner|intermediate|advanced>",
  "tags": ["<2-4 lowercase keyword tags>"],
  "confidence": <0.0-1.0>
}

Rules:
- skill_category and sub_skill MUST exactly match entries in the taxonomy above
- coaching_cue should be practical and age-appropriate
- If you cannot classify the post confidently, use "Coaching Method" / "Drill Progression" as a fallback
- Return ONLY the JSON object, no markdown, no explanation`;
}

async function callClaude(prompt, apiKey) {
  const resp = await fetch(ANTHROPIC_API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
    },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: 512,
      messages: [{ role: 'user', content: prompt }],
    }),
  });

  if (!resp.ok) {
    const body = await resp.text();
    throw new Error(`Anthropic API error ${resp.status}: ${body.slice(0, 200)}`);
  }

  const data = await resp.json();
  const text = data.content?.[0]?.text ?? '';
  // Strip potential markdown code fences
  const clean = text.replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();
  return JSON.parse(clean);
}

function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

export async function pull(flags = {}) {
  const force  = Boolean(flags.force);
  const limit  = flags.limit ? parseInt(flags.limit, 10) : Infinity;
  const dryRun = Boolean(flags['dry-run']);

  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!dryRun && !apiKey) {
    console.error('❌ ANTHROPIC_API_KEY not set in .env');
    process.exit(1);
  }

  const taxonomy = loadTaxonomy();
  const taxonomyText = buildTaxonomyText(taxonomy);

  if (!existsSync(CACHE_DIR)) {
    console.error(`❌ Cache dir not found. Run "node run.mjs rugby extract" first.`);
    process.exit(1);
  }

  // Find all raw cache files (not classified)
  const rawFiles = readdirSync(CACHE_DIR)
    .filter(f => f.endsWith('.json') && !f.endsWith('-classified.json'))
    .sort();

  console.log(`\n🧠 Rugby Post Classifier (taxonomy v${taxonomy.version})`);
  console.log(`   Model     : ${MODEL}`);
  console.log(`   Raw posts : ${rawFiles.length}\n`);

  let classified = 0, skipped = 0, failed = 0;
  let processed = 0;

  for (let i = 0; i < rawFiles.length; i++) {
    if (processed >= limit) break;

    const postId       = basename(rawFiles[i], '.json');
    const classPath    = join(CACHE_DIR, `${postId}-classified.json`);
    const rawPath      = join(CACHE_DIR, rawFiles[i]);

    // Skip if already classified with current taxonomy version
    if (!force && existsSync(classPath)) {
      const existing = JSON.parse(readFileSync(classPath, 'utf8'));
      if (existing.taxonomy_version === taxonomy.version) {
        skipped++;
        continue;
      }
    }

    processed++;
    const meta   = JSON.parse(readFileSync(rawPath, 'utf8'));
    const prompt = buildPrompt(meta, taxonomyText);

    if (dryRun) {
      console.log(`  [dry-run] Would classify: ${postId}`);
      console.log(`  Prompt preview:\n${prompt.slice(0, 300)}...\n`);
      classified++;
      continue;
    }

    process.stdout.write(`  Classifying ${postId}... `);

    let result;
    try {
      result = await callClaude(prompt, apiKey);
    } catch (err) {
      console.log(`❌  ${err.message.slice(0, 100)}`);
      failed++;
      // Batch delay even on failure to avoid hammering the API
      if (processed % BATCH_SIZE === 0) await sleep(BATCH_DELAY_MS);
      continue;
    }

    const output = {
      ...result,
      taxonomy_version: taxonomy.version,
      post_id: postId,
      classified_at: new Date().toISOString(),
    };

    writeFileSync(classPath, JSON.stringify(output, null, 2), 'utf8');
    console.log(`✅  [${output.skill_category}] ${output.sub_skill} (${output.difficulty})`);
    classified++;

    // Throttle between batches
    if (processed % BATCH_SIZE === 0) {
      process.stdout.write(`  (batch pause ${BATCH_DELAY_MS}ms)\n`);
      await sleep(BATCH_DELAY_MS);
    }
  }

  console.log(`\n📊 Summary`);
  console.log(`   Classified : ${classified}`);
  console.log(`   Skipped    : ${skipped} (already up-to-date)`);
  console.log(`   Failed     : ${failed}`);
  console.log(`   Taxonomy   : v${taxonomy.version}\n`);
}

// Direct invocation
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  // Load .env manually for direct runs
  const { config } = await import('dotenv');
  config({ path: join(VAULT_ROOT, '.env') });
  pull({}).catch(err => { console.error(err); process.exit(1); });
}

