/**
 * rugby-ingest.mjs — Generates Obsidian notes from classified rugby posts
 *                    and regenerates Rugby/Glossary.md
 *
 * Reads .cache/rugby/<id>-classified.json (+ <id>.json for metadata),
 * writes Rugby/Posts/<id>.md, and regenerates the canonical Glossary.
 *
 * Incremental: notes are skipped when their taxonomy_version matches the
 * current taxonomy. Taxonomy version bumps overwrite stale notes.
 *
 * Usage:
 *   node run.mjs rugby ingest
 *   node run.mjs rugby ingest --force      # overwrite all notes
 *   node run.mjs rugby ingest --dry-run    # preview without writing
 */

import { readFileSync, writeFileSync, existsSync, readdirSync, mkdirSync } from 'fs';
import { resolve, dirname, join, basename } from 'path';
import { fileURLToPath } from 'url';

const __dirname  = dirname(fileURLToPath(import.meta.url));
const VAULT_ROOT = resolve(__dirname, '..', '..');
const CACHE_DIR  = join(VAULT_ROOT, '.cache', 'rugby');
const POSTS_DIR  = join(VAULT_ROOT, 'Rugby', 'Posts');
const TAXONOMY_FILE = join(VAULT_ROOT, 'Rugby', 'taxonomy', 'rugby-skills.json');
const GLOSSARY_FILE = join(VAULT_ROOT, 'Rugby', 'Glossary.md');

function loadTaxonomy() {
  return JSON.parse(readFileSync(TAXONOMY_FILE, 'utf8'));
}

function formatDate(yyyymmdd) {
  if (!yyyymmdd || yyyymmdd.length < 8) return '';
  return `${yyyymmdd.slice(0, 4)}-${yyyymmdd.slice(4, 6)}-${yyyymmdd.slice(6, 8)}`;
}

function buildNote(meta, classification) {
  const uploadDate  = formatDate(meta.upload_date);
  const descExcerpt = (meta.description ?? '').slice(0, 300).replace(/\n/g, ' ').trim();
  const tags        = (classification.tags ?? []).join(', ');
  const ageGroups   = JSON.stringify(classification.age_groups ?? []);

  const frontmatter = [
    '---',
    `type: rugby_drill`,
    `post_id: ${meta.post_id}`,
    `url: "${meta.url}"`,
    `skill_category: "${classification.skill_category}"`,
    `sub_skill: "${classification.sub_skill}"`,
    `canonical_term: "${classification.canonical_term}"`,
    `coaching_cue: "${(classification.coaching_cue ?? '').replace(/"/g, "'")}"`,
    `age_groups: ${ageGroups}`,
    `difficulty: ${classification.difficulty}`,
    `taxonomy_version: "${classification.taxonomy_version}"`,
    `date_ingested: ${new Date().toISOString().slice(0, 10)}`,
    `upload_date: "${uploadDate}"`,
    `uploader: "${meta.uploader ?? ''}"`,
    `tags: [rugby, ${tags}]`,
    `confidence: ${classification.confidence ?? 0}`,
    '---',
  ].join('\n');

  const body = [
    '',
    `**[View on Instagram](${meta.url})**`,
    '',
    descExcerpt ? `> ${descExcerpt}` : '',
    '',
    `**Coaching Cue:** ${classification.coaching_cue ?? ''}`,
    '',
    `**Age Groups:** ${(classification.age_groups ?? []).join(', ')}  |  **Difficulty:** ${classification.difficulty}`,
  ].join('\n');

  return frontmatter + body;
}

function buildGlossary(taxonomy, allClassifications) {
  const today = new Date().toISOString().slice(0, 10);

  // Build lookup: sub_skill → { cues: Set, age_groups: Set, count: number }
  const skillStats = {};
  for (const cls of allClassifications) {
    const key = `${cls.skill_category}::${cls.sub_skill}`;
    if (!skillStats[key]) {
      skillStats[key] = { cues: [], age_groups: new Set(), count: 0 };
    }
    if (cls.coaching_cue) skillStats[key].cues.push(cls.coaching_cue);
    for (const ag of (cls.age_groups ?? [])) skillStats[key].age_groups.add(ag);
    skillStats[key].count++;
  }

  const lines = [
    '---',
    'title: Rugby Coaching Glossary',
    'type: glossary',
    'tags: [rugby, coaching, glossary, reference]',
    `last_updated: ${today}`,
    `taxonomy_version: "${taxonomy.version}"`,
    '---',
    '',
    '# Rugby Coaching Glossary',
    '',
    `> Canonical terminology for ${Object.values(taxonomy.categories).flat().length} skills across ${taxonomy.age_groups.join(', ')} age groups.`,
    `> Generated from taxonomy v${taxonomy.version}. All coaches should use these exact terms.`,
    '',
    '## Age Group Guide',
    '',
    ...Object.entries(taxonomy.age_group_notes ?? {}).map(
      ([ag, note]) => `- **${ag}**: ${note}`
    ),
    '',
    '---',
    '',
  ];

  for (const [category, skills] of Object.entries(taxonomy.categories)) {
    lines.push(`## ${category}`, '');
    lines.push('| Canonical Term | Age Groups | Coaching Cue | Drills |');
    lines.push('|---|---|---|---|');

    for (const skill of skills) {
      const key   = `${category}::${skill}`;
      const stats = skillStats[key];
      const count = stats?.count ?? 0;
      // Most representative coaching cue (most common, or first)
      const cue   = stats?.cues[0] ?? '—';
      const ageGrps = stats
        ? [...stats.age_groups].filter(ag => taxonomy.age_groups.includes(ag)).join(', ') || 'All'
        : '—';
      lines.push(`| ${skill} | ${ageGrps} | ${cue} | ${count} |`);
    }
    lines.push('');
  }

  lines.push('---');
  lines.push('');
  lines.push(`*Auto-generated by \`rugby-ingest.mjs\` — do not edit manually. Update \`Rugby/taxonomy/rugby-skills.json\` to change terminology.*`);

  return lines.join('\n');
}

export async function pull(flags = {}) {
  const force  = Boolean(flags.force);
  const dryRun = Boolean(flags['dry-run']);

  mkdirSync(POSTS_DIR, { recursive: true });

  const taxonomy = loadTaxonomy();

  if (!existsSync(CACHE_DIR)) {
    console.error('❌ No cache found. Run "node run.mjs rugby extract" then "node run.mjs rugby classify" first.');
    process.exit(1);
  }

  const classifiedFiles = readdirSync(CACHE_DIR)
    .filter(f => f.endsWith('-classified.json'))
    .sort();

  console.log(`\n📝 Rugby Note Ingest (taxonomy v${taxonomy.version})`);
  console.log(`   Classified posts : ${classifiedFiles.length}\n`);

  let written = 0, skipped = 0;
  const allClassifications = [];

  for (const file of classifiedFiles) {
    const postId    = basename(file, '-classified.json');
    const clsPath   = join(CACHE_DIR, file);
    const rawPath   = join(CACHE_DIR, `${postId}.json`);
    const notePath  = join(POSTS_DIR, `${postId}.md`);

    if (!existsSync(rawPath)) {
      console.log(`  ⚠️  No raw metadata for ${postId} — skipping`);
      continue;
    }

    const classification = JSON.parse(readFileSync(clsPath, 'utf8'));
    allClassifications.push(classification);

    // Skip if note exists and taxonomy version matches
    if (!force && existsSync(notePath)) {
      const existing = readFileSync(notePath, 'utf8');
      if (existing.includes(`taxonomy_version: "${taxonomy.version}"`)) {
        skipped++;
        continue;
      }
    }

    if (dryRun) {
      console.log(`  [dry-run] Would write: Rugby/Posts/${postId}.md  [${classification.skill_category} / ${classification.sub_skill}]`);
      written++;
      continue;
    }

    const meta = JSON.parse(readFileSync(rawPath, 'utf8'));
    const note = buildNote(meta, classification);
    writeFileSync(notePath, note, 'utf8');
    console.log(`  ✅ ${postId}.md  [${classification.skill_category} / ${classification.sub_skill}]`);
    written++;
  }

  // Regenerate glossary
  console.log('\n  Regenerating Glossary.md...');
  const glossary = buildGlossary(taxonomy, allClassifications);
  if (!dryRun) {
    writeFileSync(GLOSSARY_FILE, glossary, 'utf8');
    console.log('  ✅ Rugby/Glossary.md updated');
  } else {
    console.log('  [dry-run] Would update Rugby/Glossary.md');
  }

  console.log(`\n📊 Summary`);
  console.log(`   Written  : ${written}`);
  console.log(`   Skipped  : ${skipped} (already up-to-date)`);
  console.log(`   Glossary : Rugby/Glossary.md\n`);
}

// Direct invocation
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  pull({}).catch(err => { console.error(err); process.exit(1); });
}

